def _curated_fact_source(text):
    """True όταν μια κάρτα έχει επιμελημένη πλήρη ελληνική απόδοση."""
    core = str(text).strip()
    tag_match = re.match(r"^\[[^\]]+\]\s*(.*)$", core, flags=re.DOTALL)
    if tag_match:
        core = tag_match.group(1).strip()
    if core in EL_EXACT:
        return True
    universal = re.match(r"^(.+?) fact:\s*(.*)$", core, flags=re.IGNORECASE | re.DOTALL)
    if universal and universal.group(2).casefold() in EL_UNIVERSAL_FACTS:
        return True
    return bool(re.search(r"[Α-Ωα-ωΆΈΉΊΌΎΏάέήίόύώϊΐϋΰ]", core) and not re.search(r"[A-Za-z]{2,}", core))


