def _el_combat_name(value):
    name = str(value)
    wild = re.fullmatch(r"Wild (.+)", name, flags=re.I)
    if wild:
        return f"Άγριος αντίπαλος ({el_species(wild.group(1))})"
    return "Φιλαράκι" if name.casefold() == "buddy" else name


