# Μεγαλύτερες φράσεις πρώτα για να αποφεύγονται μερικές αντικαταστάσεις.
_EL_PHRASE_ITEMS = sorted(
    list(EL_SPECIES.items()) + list(EL_PHRASES.items()),
    key=lambda item: len(item[0]),
    reverse=True,
)
_EL_PHRASE_LOOKUP = {source.casefold(): target for source, target in _EL_PHRASE_ITEMS}
_EL_PHRASE_RE = re.compile(
    r"(?<![A-Za-z])(?:"
    + "|".join(re.escape(source) for source, _target in _EL_PHRASE_ITEMS)
    + r")(?![A-Za-z])",
    flags=re.IGNORECASE,
)

def _replace_known_phrase(match):
    return _EL_PHRASE_LOOKUP.get(match.group(0).casefold(), match.group(0))
_EL_PROTECTED_RE = re.compile(
    r"https?://\S+|(?:[A-Za-z]:)?(?:[/~][^\s|]+)|\[[^\]\n]{1,18}\]|"
    r"\b(?:LAN|SFX|XP|HP|WAV|JSON|TCP|UDP|IP|IPv4|Wi-Fi|Termux|Android|Python|mpv|ffplay|aplay|PSI|COVID-19|WWF|CITES|GPS|DNA|UV|API|ASCII|HTTP|HTTPS|GitHub|Linux)\b|"
    r"\b\d+(?:\.\d+){1,3}\b"
)
_EL_WORD_RE = re.compile(r"[A-Za-z]+(?:['’][A-Za-z]+)?")

class RawDisplay(str):
    """Κείμενο που έχει ήδη μεταφραστεί ή πρέπει να εμφανιστεί αυτούσιο."""


def raw_display(value):
    return RawDisplay(str(value))


def el_species(name):
    value = str(name)
    return EL_SPECIES.get(value, value)


def _looks_like_ascii_art(text):
    if "\n" in text:
        return False
    letters = sum(ch.isalpha() for ch in text)
    art_symbols = sum(ch in "/\\_|()[]{}<>^~`'\"=-+*:.@#" for ch in text)
    return art_symbols >= 3 and art_symbols > letters * 2


def _transliterate_unknown(word):
    """Έσχατη λύση για σπάνια ονόματα/όρους που δεν υπάρχουν στο λεξιλόγιο."""
    lower = word.lower()
    pairs = (
        ("tion", "σιον"), ("sion", "ζιον"), ("ture", "τσουρ"), ("ough", "ο"),
        ("igh", "άι"), ("ph", "φ"), ("th", "θ"), ("ch", "χ"), ("sh", "σ"),
        ("ps", "ψ"), ("qu", "κου"), ("ck", "κ"), ("ng", "νγκ"), ("ee", "ι"),
        ("oo", "ου"), ("ou", "ου"), ("ai", "αι"), ("ei", "ει"), ("au", "αου"),
    )
    for source, target in pairs:
        lower = lower.replace(source, target)
    table = str.maketrans({
        "a":"α", "b":"μπ", "c":"κ", "d":"ντ", "e":"ε", "f":"φ", "g":"γκ",
        "h":"χ", "i":"ι", "j":"τζ", "k":"κ", "l":"λ", "m":"μ", "n":"ν",
        "o":"ο", "p":"π", "q":"κ", "r":"ρ", "s":"σ", "t":"τ", "u":"ου",
        "v":"β", "w":"γου", "x":"ξ", "y":"ι", "z":"ζ",
    })
    return lower.translate(table)


def _translate_word(match):
    word = match.group(0)
    key = word.casefold().replace("’", "'")
    possessive = key.endswith("'s")
    if possessive:
        key = key[:-2]
    translated = EL_WORDS.get(key)
    if translated is not None:
        return translated + (" του" if possessive else "")
    if word in TECHNICAL_TERMS or word.isupper() or len(word) == 1:
        return word
    # Άγνωστα κύρια ονόματα και τεχνικοί όροι διατηρούνται αυτούσια. Δεν
    # χρησιμοποιείται φωνητική μεταγραφή, επειδή θα παρήγαγε ψευδοελληνικό κείμενο.
    return word


def _translate_word_strict(match):
    """Μετάφραση που αφήνει άγνωστες λέξεις ορατές για ποιοτικό φιλτράρισμα."""
    word = match.group(0)
    key = word.casefold().replace("’", "'")
    possessive = key.endswith("'s")
    if possessive:
        key = key[:-2]
    translated = EL_WORDS.get(key)
    if translated is not None:
        return translated + (" του" if possessive else "")
    return word


@functools.lru_cache(maxsize=65536)
def el_text(value, strict=False):
    """Μεταφράζει κάθε εμφανιζόμενο μήνυμα χωρίς να αγγίζει δεδομένα/saves."""
    if value is None:
        return ""
    text = str(value)
    if not text or isinstance(value, RawDisplay) or _looks_like_ascii_art(text):
        return text
    # Ήδη ελληνικό κείμενο χωρίς αγγλικές λέξεις.
    if re.search(r"[Α-Ωα-ωΆΈΉΊΌΎΏάέήίόύώϊΐϋΰ]", text) and not re.search(r"[A-Za-z]{2,}", text):
        return text

    leading = text[:len(text) - len(text.lstrip())]
    trailing = text[len(text.rstrip()):]
    core = text.strip()
    for source_tag, target_tag in EL_TAGS.items():
        core = core.replace(source_tag, target_tag)

    universal_match = re.match(
        r"^(\[[^\]]+\]\s*)?(.+?) fact:\s*(.*)$", core,
        flags=re.IGNORECASE | re.DOTALL,
    )
    if universal_match:
        tag, species_name, universal_body = universal_match.groups()
        template = EL_UNIVERSAL_FACTS.get(universal_body.casefold())
        if template is not None:
            return leading + (tag or "") + template.format(species=el_species(species_name.strip())) + trailing

    exact = EL_EXACT.get(core)
    if exact is not None:
        return leading + exact + trailing

    for pattern, replacement_text in EL_DYNAMIC_PATTERNS:
        match = pattern.fullmatch(core)
        if match:
            translated_dynamic = (
                replacement_text(*match.groups())
                if callable(replacement_text)
                else replacement_text.format(*match.groups())
            )
            return leading + translated_dynamic + trailing

    # Οι εκπαιδευτικές κάρτες έχουν πρόθεμα κατηγορίας. Μεταφράζουμε
    # ολόκληρο το σώμα της κάρτας όταν υπάρχει επιμελημένη απόδοση.
    category_match = re.match(r"^(\[[^\]]+\])\s*(.*)$", core, flags=re.DOTALL)
    if category_match:
        category, body = category_match.groups()
        exact_body = EL_EXACT.get(body)
        if exact_body is not None:
            return leading + category + " " + exact_body + trailing

    protected = []
    def protect(match):
        protected.append(match.group(0))
        return f"\ue100{len(protected)-1}\ue101"
    working = _EL_PROTECTED_RE.sub(protect, core)

    working = _EL_PHRASE_RE.sub(_replace_known_phrase, working)
    working = _EL_WORD_RE.sub(_translate_word_strict if strict else _translate_word, working)
    for index, original in enumerate(protected):
        working = working.replace(f"\ue100{index}\ue101", original)
    return leading + working + trailing


def display_text(value):
    return str(value) if isinstance(value, RawDisplay) else el_text(value)


def display_len(value):
    return len(display_text(value))


class GreekWindow:
    """Διαφανής προσαρμογέας curses που μεταφράζει όλα τα addstr/addnstr."""
    def __init__(self, window):
        self._window = window

    def __getattr__(self, name):
        return getattr(self._window, name)

    @staticmethod
    def _text_index(args):
        if not args:
            return None
        if len(args) >= 3 and isinstance(args[0], int) and isinstance(args[1], int):
            return 2
        return 0

    def addstr(self, *args):
        values = list(args)
        index = self._text_index(values)
        if index is not None and index < len(values) and isinstance(values[index], str):
            values[index] = display_text(values[index])
        return self._window.addstr(*values)

    def addnstr(self, *args):
        values = list(args)
        index = self._text_index(values)
        if index is not None and index < len(values) and isinstance(values[index], str):
            values[index] = display_text(values[index])
        return self._window.addnstr(*values)


